/// GM drum map: MIDI note -> index into DRUM_PATCHES.
/// 0xFF = unmapped (note is ignored on drum channel).
#[rustfmt::skip]
const DRUM_MAP: [u8; 128] = [
    0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, // 0-15
    0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, // 16-31
    0xFF, 0xFF, 0xFF,    0,    0,   12,    1,    6,    2,    5,    3,    5,    3,    5,    4,    5, // 32-47
       5,   16,    5,   16,   16,   17,    7,   16,   17,   16,   15,   16,   11,   11,   10,   10, // 48-63
      10,    9,    9,   13,   13,   20,   15,   21,   21,   19,   19,   18,   12,   12,   22,   22, // 64-79
       8,    8, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, // 80-95
    0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, // 96-111
    0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, 0xFF, // 112-127
];

/// Look up the DX7 percussion patch for a GM drum note.
/// Returns `None` if the note has no drum mapping.
pub fn drum_voice(note: u8) -> Option<DxVoice> {
    let idx = DRUM_MAP[note as usize];
    if idx == 0xFF {
        return None;
    }
    Some(DxVoice::from_packed(&DRUM_PATCHES[idx as usize]))
}
